/**
 * ConfirmDialog — standardized confirm/destructive prompt.
 *
 * Replaces the bespoke Cancel/Confirm dialog blocks across BusinessDisplay,
 * EventEdit, AdminDeletedList, ProfileInfoDialog, etc. Single source of truth
 * for spacing, button order, ARIA attributes, busy state, and color semantics.
 */
import * as React from 'react';
import {
    Button,
    CircularProgress,
    Dialog,
    DialogActions,
    DialogContent,
    DialogContentText,
    DialogTitle,
} from '@mui/material';

export type ConfirmTone = 'primary' | 'error' | 'success' | 'warning' | 'info';

export interface ConfirmDialogProps {
    /** Controls visibility. */
    open: boolean;
    /** Called when the user cancels (button or backdrop). Ignored while busy. */
    onCancel: () => void;
    /** Called when the user confirms. */
    onConfirm: () => void;
    /** Dialog title (rendered as the heading). */
    title: React.ReactNode;
    /** Body content — either a string or arbitrary nodes. */
    description: React.ReactNode;
    /** Confirm button label. Defaults to "Confirm". */
    confirmLabel?: string;
    /** Cancel button label. Defaults to "Cancel". */
    cancelLabel?: string;
    /** Color tone for the confirm button. Defaults to `primary`. */
    tone?: ConfirmTone;
    /** When true, shows a busy spinner in the confirm button and locks both buttons. */
    busy?: boolean;
    /** Label shown while busy. Defaults to "Working...". */
    busyLabel?: string;
}

export const ConfirmDialog: React.FC<ConfirmDialogProps> = ({
    open,
    onCancel,
    onConfirm,
    title,
    description,
    confirmLabel = 'Confirm',
    cancelLabel = 'Cancel',
    tone = 'primary',
    busy = false,
    busyLabel = 'Working...',
}) => {
    const handleClose = () => {
        if (!busy) onCancel();
    };

    return (
        <Dialog
            open={open}
            onClose={handleClose}
            maxWidth="xs"
            fullWidth
            aria-labelledby="confirm-dialog-title"
            aria-describedby="confirm-dialog-description"
        >
            <DialogTitle id="confirm-dialog-title">{title}</DialogTitle>
            <DialogContent>
                {typeof description === 'string' ? (
                    <DialogContentText id="confirm-dialog-description">
                        {description}
                    </DialogContentText>
                ) : (
                    <div id="confirm-dialog-description">{description}</div>
                )}
            </DialogContent>
            <DialogActions>
                <Button onClick={onCancel} color="inherit" disabled={busy}>
                    {cancelLabel}
                </Button>
                <Button
                    onClick={onConfirm}
                    color={tone}
                    variant="contained"
                    disabled={busy}
                    startIcon={busy ? <CircularProgress size={16} color="inherit" /> : undefined}
                >
                    {busy ? busyLabel : confirmLabel}
                </Button>
            </DialogActions>
        </Dialog>
    );
};

export default ConfirmDialog;
